const input = $json.body;
const jobId = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => { const r = Math.random() * 16 | 0; return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16); });

return [{
  json: {
    job_id: jobId,
    avatar_id: input.avatar_id,
    script: input.script,
    background_id: input.background_id,
    music_url: input.music_url || null
  }
}];

const avatar = $('Lookup Avatar').first().json;
const initData = $('Init Job').first().json;

const voiceSettings = typeof avatar.voice_settings === 'string'
  ? JSON.parse(avatar.voice_settings)
  : (avatar.voice_settings || {});

return [{
  json: {
    voice_id: avatar.voice_id,
    tts_body: {
      text: initData.script,
      model_id: 'eleven_multilingual_v2',
      voice_settings: {
        stability: voiceSettings.stability || 0.5,
        similarity_boost: voiceSettings.similarity_boost || 0.75
      }
    }
  }
}];

const ttsResponse = $input.first().json;
const audioBase64 = ttsResponse.audio_base64;

if (!audioBase64) {
  throw new Error('No audio_base64 in ElevenLabs response');
}

console.log('Got TTS audio, uploading to temp service...');

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://temp-audio-service-production.up.railway.app/audio',
  headers: { 'Content-Type': 'application/json' },
  body: { audio_base64: audioBase64, format: 'mp3' },
  json: true
});

console.log('Temp audio URL: ' + response.url);

return [{ json: { tts_audio_url: response.url } }];

const silenceResult = $input.first().json;
const audioUrl = silenceResult.audio_url || silenceResult.url;
const avatar = $('Lookup Avatar').first().json;

console.log('Audio with silence: ' + audioUrl);
console.log('Motion avatar ID: ' + avatar.motion_avatar_id);

return [{
  json: {
    heygen_body: {
      title: 'Quick Take',
      video_inputs: [{
        character: {
          type: 'talking_photo',
          talking_photo_id: avatar.motion_avatar_id
        },
        voice: {
          type: 'audio',
          audio_url: audioUrl
        }
      }],
      dimension: { width: 720, height: 1280 }
    }
  }
}];

const response = $input.first().json;
const videoId = response.data && response.data.video_id;

if (!videoId) {
  throw new Error('No video_id from HeyGen: ' + JSON.stringify(response));
}

console.log('HeyGen video ID: ' + videoId);

return [{ json: { heygen_video_id: videoId } }];

const status = $('API: HeyGen Status').first().json;
const videoUrl = status.data.video_url;
const duration = status.data.duration;

console.log('HeyGen video ready: ' + videoUrl);
console.log('Duration: ' + duration + 's');

return [{ json: { heygen_video_url: videoUrl, heygen_duration: duration } }];

const response = $input.first().json;
const pollUrl = response.urls && response.urls.get;

if (!pollUrl) {
  throw new Error('No poll URL from Replicate: ' + JSON.stringify(response));
}

console.log('RVM poll URL: ' + pollUrl);

return [{ json: { rvm_poll_url: pollUrl } }];

const rvmResult = $('API: RVM Status').first().json;
const alphaUrl = rvmResult.output;

if (!alphaUrl) {
  throw new Error('No alpha video URL from RVM: ' + JSON.stringify(rvmResult));
}

console.log('Alpha mask video: ' + alphaUrl);

return [{ json: { alpha_video_url: alphaUrl } }];

const initData = $('Init Job').first().json;
const bg = $('Lookup Background').first().json;
const heygenUrl = $('Parse HeyGen Result').first().json.heygen_video_url;
const heygenDuration = $('Parse HeyGen Result').first().json.heygen_duration;
const alphaUrl = $('Parse RVM Result').first().json.alpha_video_url;
const musicUrl = initData.music_url;

console.log('Setting video duration to HeyGen duration: ' + heygenDuration + 's');

const elements = [
  {
    type: 'image',
    source: bg.cloudinary_url,
    width: '100%',
    height: '100%',
    fit: 'cover',
    track: 1
  },
  {
    type: 'composition',
    track: 5,
    x: '50%',
    y: '55%',
    width: '85%',
    height: '85%',
    elements: [
      {
        type: 'video',
        name: 'avatar-1',
        source: heygenUrl,
        width: '100%',
        height: '100%',
        fit: 'contain',
        volume: '100%'
      },
      {
        type: 'video',
        name: 'avatar-1-mask',
        source: alphaUrl,
        width: '100%',
        height: '100%',
        fit: 'contain',
        mask_mode: 'luma'
      }
    ]
  }
];

if (musicUrl) {
  elements.push({
    type: 'audio',
    source: musicUrl,
    track: 2,
    volume: '10%'
  });
}

const source = {
  output_format: 'mp4',
  width: 720,
  height: 1280,
  duration: heygenDuration,
  elements: elements
};

console.log('Creatomate source built, duration: ' + heygenDuration + 's');

return [{ json: { source: source } }];

const response = $input.first().json;
const renders = Array.isArray(response) ? response : [response];
const renderId = renders[0] && renders[0].id;

if (!renderId) {
  throw new Error('No render ID from Creatomate: ' + JSON.stringify(response));
}

console.log('Creatomate render ID: ' + renderId);

return [{ json: { render_id: renderId } }];

